final:
module RefModule (
    input wire clk,
    input wire [3:0] instruction,
    output reg [1:0] opcode,
    output reg [1:0] operand
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        opcode <= instruction[3:2];
        operand <= instruction[1:0];
    end
endmodule
